import base64
import logging
from typing import Any, Dict, List

import cloudfunctions.context
import google.auth.appengine
import pickle
from google.cloud import tasks_v2
from google.cloud.pubsublite.proto.services import messaging_pb2

logging.basicConfig(level=logging.INFO)

def process_pub_sub_messages(data: bytes) -> str:
    message = messaging_pb2.ReceivedMessage()
    message.ParseFromString(data)
    
    try:
        serialized_data = base64.b64decode(message.data.encode())
        data: Dict[str, Any] = pickle.loads(serialized_data)
        
        # Process the task here
        for task in data['tasks']:
            with tasks_v2.CloudTasksClient() as client:
                task_name = task.name
                queue_path = task.queue_path
                
                client.delete_if_exists(
                    request=tasks_v2.DeleteIfExistsQueueRequest(
                        name=queue_path,
                        if_none_match=task.etag
                    )
                )
                
    except Exception as e:
        logging.error(f"Error processing task: {e}")
        
    return "Tasks processed successfully"

def process_pub_sub_message(context):
    try:
        data = base64.b64decode(context.data.encode())
        result = process_pub_sub_messages(data)
        context.attributes['message-processing-result'] = result
    except Exception as e:
        logging.error(f"Error processing Pub/Sub message: {e}")